void ui_event_click_Red(lv_event_t * e)
{
		if(lv_event_get_code(e) == LV_EVENT_CLICKED) 
		{
			// 1. 洗掉所有按钮的红色
			Reset_All_Mode_Buttons_Color();
			
			// 2. 唯独把自己染成红色！
			lv_obj_set_style_bg_color(ui_Button1, ACTIVE_BTN_COLOR, 0);
			
			// 3. 执行你的底层模式切换逻辑
			current_mode = Red;
			input_source = 3;  
			input_flag = 1;    	
		}
}

